import React, { useState } from 'react';
import { useAuth } from './AuthContext';
import LoginModal from './LoginModal';
import RegisterModal from './RegisterModal';
import './Header.css';

const Header = () => {
    const [showLogin, setShowLogin] = useState(false);
    const [showRegister, setShowRegister] = useState(false);
    const { user, logout } = useAuth();

    console.log('Header render - user:', user); // Debug log

    return (
        <>
            <header>
                <div className="container">
                    <nav>
                        <div className="logo">
                            <a href="#home">
                                <h1>Auto<span>Vip</span></h1>
                            </a>
                        </div>
                        <ul className="nav-menu">
                            <li><a href="#home">Trang Chủ</a></li>
                            <li><a href="#cars">Xe</a></li>
                            <li><a href="#brands">Thương Hiệu</a></li>
                            {user && user.role === 'admin' && (
                                <li><a href="#admin">Quản Lý</a></li>
                            )}
                        </ul>
                        <div className="nav-buttons">
                            {user ? (
                                <>
                                    <span className="welcome-text">
                                        👋 Xin chào, <strong>{user.fullname || user.name}</strong>
                                        {user.role === 'admin' && ' (Admin)'}
                                    </span>
                                    <button onClick={logout} className="btn-logout">
                                        Đăng Xuất
                                    </button>
                                </>
                            ) : (
                                <>
                                    <button 
                                        onClick={() => {
                                            console.log('Click đăng nhập');
                                            setShowLogin(true);
                                        }} 
                                        className="btn-login"
                                    >
                                        Đăng Nhập
                                    </button>
                                    <button 
                                        onClick={() => {
                                            console.log('Click đăng ký');
                                            setShowRegister(true);
                                        }} 
                                        className="btn-register"
                                    >
                                        Đăng Ký
                                    </button>
                                </>
                            )}
                        </div>
                    </nav>
                </div>
            </header>

            <LoginModal 
                isOpen={showLogin}
                onClose={() => {
                    console.log('Đóng login modal');
                    setShowLogin(false);
                }}
                onSwitchToRegister={() => {
                    console.log('Chuyển sang đăng ký');
                    setShowLogin(false);
                    setShowRegister(true);
                }}
            />

            <RegisterModal 
                isOpen={showRegister}
                onClose={() => {
                    console.log('Đóng register modal');
                    setShowRegister(false);
                }}
                onSwitchToLogin={() => {
                    console.log('Chuyển sang đăng nhập');
                    setShowRegister(false);
                    setShowLogin(true);
                }}
            />
        </>
    );
};

export default Header;
